  return JSON.stringify(expected) === JSON.stringify(actual);
}

// Result type
interface EvalResult {
  benchmarkId: string;
  success: boolean;
  timeMs: number;
  expectedOutput: any;
  actualOutput: any;
}

// Offline evaluation runner class
export class OfflineEvalRunner {
  private skill: Skill;
  private benchmarks: Benchmark[];

  constructor(skill: Skill, benchmarks: unknown[]) {
    this.skill = skill;
    // Validate benchmarks
    this.benchmarks = benchmarks.map((b, i) => {
      const parsed = BenchmarkSchema.safeParse(b);
      if (!parsed.success) {
        throw new Error(`Benchmark at index ${i} failed validation: ${parsed.error}`);
      }
      return parsed.data;
    });
  }

  async run(): Promise<EvalResult[]> {
    const results: EvalResult[] = [];

    for (const benchmark of this.benchmarks) {
      const start = performance.now();

      // Run the skill with the input
      let actualOutput: any;
      try {
        actualOutput = await this.skill.invoke(benchmark.input as SkillInput);
      } catch (err) {
        actualOutput = { error: (err as Error).message };
      }

      const end = performance.now();
      const timeMs = end - start;

      // Grade the output
      const success = gradeOutput(benchmark.expectedOutput, actualOutput);

      results.push({
        benchmarkId: benchmark.id,
        success,
        timeMs,
        expectedOutput: benchmark.expectedOutput,
        actualOutput,
      });
    }

    return results;
  }

